const body = $input.first().json.body || $input.first().json;

const query      = body.query      || '';
const context    = body.context    || '';
const session_id = body.session_id || 'unknown';
const user_id    = body.user_id    || null;

const systemPrompt = `You are AURA-AI, the official AI assistant for AURA-WEAR — a premium custom clothing brand based in Pakistan.

You help customers with:
- Fabric recommendations (Cotton, Fleece, Polyester, Blended) and GSM grades
- Garment types (T-Shirts, Hoodies, Jackets, Sports Uniforms)
- Print methods (DTG, Screen Print, Embroidery, Heat Transfer)
- Order tracking and status updates
- Pricing in PKR including GST and shipping

RULES:
- Answer ONLY based on the database context provided
- When order data is in context, clearly state the order ID, status, and total
- Keep answers concise (2-4 sentences), friendly and professional
- Always quote prices in PKR
- Never mention internal system names like database connectors or APIs`;

const userMessage = `DATABASE CONTEXT:\n${context}\n\nCUSTOMER QUESTION:\n${query}`;

// Build Gemini API request body
const geminiBody = {
  systemInstruction: { parts: [{ text: systemPrompt }] },
  contents: [{ role: 'user', parts: [{ text: userMessage }] }],
  generationConfig: { temperature: 0.3, maxOutputTokens: 512 }
};

return [{ json: { query, context, session_id, user_id, geminiBody } }];

const data = $input.first().json;

let reply = '';

try {
  // Gemini response: candidates[0].content.parts[0].text
  reply = data.candidates?.[0]?.content?.parts?.[0]?.text || '';
} catch(e) {
  reply = '';
}

if (!reply) {
  reply = 'I am unable to generate a response right now. Please try again shortly.';
}

return [{ json: { output: reply.trim() } }];
